class Sink:
    """Batched inserts per table, staged through temp CSVs and COPY.

    duckdb's executemany runs row-by-row (~100x slower); COPY ingests each
    batch in one shot with no extra dependencies.
    """

    def __init__(self, con):
        self.con = con
        self.buf = {}
        self.counts = {}

    def add(self, table, row):
        self.buf.setdefault(table, []).append(row)
        self.counts[table] = self.counts.get(table, 0) + 1
        if len(self.buf[table]) >= BATCH:
            self.flush(table)

    def flush(self, table=None):
        import csv
        import os
        import tempfile
        for t in [table] if table else list(self.buf):
            rows = self.buf.get(t) or []
            if not rows:
                continue
            fd, tmp = tempfile.mkstemp(suffix=".csv")
            os.close(fd)
            try:
                with open(tmp, "w", newline="", encoding="utf-8") as f:
                    csv.writer(f).writerows(rows)
                self.con.execute(
                    f"COPY {t} FROM '{tmp.replace(chr(92), '/')}' "
                    f"(FORMAT csv, HEADER false)")
            finally:
                os.unlink(tmp)
            self.buf[t] = []

